export const scrollViewHtml = `<!--
  固定结构：layerscoper-scrollview-* 为插件约定结构
-->
<!-- 这里的 id 建议与 LayerScoper 中该滚动区域所在的图层 id 保持一致，便于一眼看出这是“某个图层里的滚动区域容器”，而不是一个单独页面节点。 -->
<div id="layer-scrollview-id">
  <!-- 整个 ScrollView 布局（左右结构） -->
  <div class="layerscoper-scrollview-wrap">
    <!-- 左侧文本区域容器（设置 overflow 并隐藏系统默认滚动条，真正的滚动容器） -->
    <div class="layerscoper-scrollview-content">
      <!-- 内层：宽高 100% 或由内容撑开，作为溢出的部分 -->
      <div class="layerscoper-scrollview-content-inner">
        ... 很长很长的文本或内容，但整体没有可获焦元素 ...
      </div>
    </div>
    <!-- 右侧滚动条轨道（track） -->
    <div class="layerscoper-scrollview-bar scoped" data-scoped="1">
      <!-- 滑块（thumb），唯一可聚焦元素 -->
      <div class="layerscoper-scrollview-thumb incontroll" clickfocus="onClickThumb"></div>
    </div>
  </div>
</div>

`;

export const scrollViewJs = `import { LayerScoper } from 'layer-scoper';
import { LayerScoperScrollView } from 'layer-scoper/plugin/LayerScoperScrollView.js';

const controllerCase = new LayerScoper();

const verticalScrollViewCase = new LayerScoperScrollView({
  id: 'layer-scrollview-id',
  scrollDirection: 'vertical', // 'vertical' | 'horizontal'
  scrollBarConfig: {
    trackWidth: '8px',
    trackBackground: 'rgba(255,255,255,0)',
    trackBorderRadius: '0',
    thumbColor: 'rgb(25, 170, 6)',
    thumbBorderRadius: '4px',
  },
  step: 80, // 每次按键滚动的像素距离
});

controllerCase.initController({
  id: 'layer-scrollview-id',
  className: 'incontroll',
  defaultPoint: { y: 1, x: 1 },
  // 将“指定 scope”与插件实例关联起来
  scrollViewComponentConfig: [
    {
      scope: 1,
      target: verticalScrollViewCase,
    },
  ],
  selfDefinedCallBackFn: {
    onClickThumb: this.onClickThumb,
  },
});

// 内容变化导致滚动条显示状态变化时
// verticalScrollViewCase.updateScrollView();
// controllerCase.update({ id: 'layer-scrollview-id', needUpdateScoped: 1 });
`;
